1	/**
2	 * Build Info
3	 *
4	 * Captures git commit SHA, dirty flag, and SDK version at runtime so test
5	 * results can be unambiguously tied to the build that produced them.
6	 *
7	 * Invalid-build contamination (e.g. Opus 4.7 runs against a pre-fix Bedrock
8	 * client) is otherwise only visible by grepping error strings across result
9	 * JSONs. Stamping provenance makes it a one-field check.
10	 */
11	
12	import { execSync } from "node:child_process";
13	import { readFileSync } from "node:fs";
14	import { join } from "node:path";
15	
16	export interface BuildInfo {
17	  /** Short git SHA of HEAD at runtime, or "unknown" if outside a git repo */
18	  gitSha: string;
19	  /** True if the working tree has uncommitted changes */
20	  gitDirty: boolean;
21	  /** Version of @anthropic-ai/claude-agent-sdk from package.json */
22	  sdkVersion: string;
23	  /** ISO timestamp at capture */
24	  capturedAt: string;
25	  /** AWS region used for Bedrock calls */
26	  bedrockRegion: string;
27	}
28	
29	export interface RunInvocation {
30	  /** Full Bedrock model ID used for this run */
31	  modelId: string;
32	  /** ISO timestamp of the first model call in the run */
33	  modelInvokedAt: string;
34	}
35	
36	let cached: BuildInfo | null = null;
37	
38	export function getBuildInfo(): BuildInfo {
39	  if (cached) return cached;
40	
41	  let gitSha = process.env.GIT_COMMIT ?? "unknown";
42	  let gitDirty = process.env.GIT_DIRTY === "true";
43	  if (gitSha === "unknown") {
44	    try {
45	      gitSha = execSync("git rev-parse --short HEAD", { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] }).trim();
46	      const status = execSync("git status --porcelain", { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] });
47	      gitDirty = status.trim().length > 0;
48	    } catch {
49	      // Not a git repo or git unavailable — leave defaults
50	    }
51	  }
52	
53	  let sdkVersion = "unknown";
54	  try {
55	    const pkgPath = join(import.meta.dirname, "..", "package.json");
56	    const pkg = JSON.parse(readFileSync(pkgPath, "utf8"));
57	    sdkVersion = pkg.dependencies?.["@anthropic-ai/claude-agent-sdk"] ?? "unknown";
58	  } catch {
59	    // package.json unreadable — leave default
60	  }
61	
62	  cached = {
63	    gitSha,
64	    gitDirty,
65	    sdkVersion,
66	    capturedAt: new Date().toISOString(),
67	    bedrockRegion: process.env.BEDROCK_REGION ?? process.env.AWS_REGION ?? process.env.AWS_DEFAULT_REGION ?? "unknown",
68	  };
69	  return cached;
70	}
71	
72	export function makeRunInvocation(modelId: string): RunInvocation {
73	  return { modelId, modelInvokedAt: new Date().toISOString() };
74	}
